 1	import * as React from 'react';
 2	import { MAX_TAGS } from '@odf/core/constants/s3-iam';
 3	import { IamUserDetails } from '@odf/core/types';
 4	import { DASH, LoadingBox, StatusBox, useCustomTranslation } from '@odf/shared';
 5	import { SectionHeading } from '@odf/shared/heading/page-heading';
 6	import { IamCommands } from '@odf/shared/iam';
 7	import {
 8	  Alert,
 9	  AlertVariant,
10	  EmptyState,
11	  EmptyStateHeader,
12	  EmptyStateVariant,
13	} from '@patternfly/react-core';
14	import { Table, Thead, Tr, Th, Tbody, Td } from '@patternfly/react-table';
15	import { useUserDetails } from '../hooks/useUserDetails';
16	
17	type TagsDetailsProps = {
18	  obj: IamUserDetails;
19	};
20	
21	type TagsDetailsContentProps = {
22	  userName: string;
23	  iamClient: IamCommands;
24	};
25	
26	const TagsDetailsContent: React.FC<TagsDetailsContentProps> = ({
27	  userName,
28	  iamClient,
29	}) => {
30	  const { t } = useCustomTranslation();
31	
32	  const {
33	    userDetails,
34	    isLoading: isLoadingUserDetails,
35	    error: userDetailsError,
36	  } = useUserDetails(userName, iamClient);
37	
38	  const tags = userDetails?.Tags || [];
39	  const remainingTags = MAX_TAGS - tags.length;
40	
41	  if (isLoadingUserDetails || userDetailsError) {
42	    return (
43	      <StatusBox loaded={!isLoadingUserDetails} loadError={userDetailsError} />
44	    );
45	  }
46	
47	  if (tags.length === 0) {
48	    return (
49	      <EmptyState variant={EmptyStateVariant.lg}>
50	        <EmptyStateHeader titleText={t('No tags found')} headingLevel="h4" />
51	      </EmptyState>
52	    );
53	  }
54	
55	  return (
56	    <div className="odf-m-pane__body">
57	      <div className="pf-v6-u-mt-md">
58	        <SectionHeading text={t('Tags')} />
59	        <Alert
60	          title={t('You can add {{remaining}} more tags', {
61	            remaining: remainingTags,
62	          })}
63	          variant={AlertVariant.info}
64	          isInline
65	        />
66	        <Table variant="compact" borders={true}>
67	          <Thead>
68	            <Tr>
69	              <Th>{t('Key')}</Th>
70	              <Th>{t('Value')}</Th>
71	            </Tr>
72	          </Thead>
73	          <Tbody>
74	            {tags.map((tag: { Key: string; Value: string }) => (
75	              <Tr key={tag.Key}>
76	                <Td dataLabel={t('Key')}>{tag.Key || DASH}</Td>
77	                <Td dataLabel={t('Value')}>{tag.Value || DASH}</Td>
78	              </Tr>
79	            ))}
80	          </Tbody>
81	        </Table>
82	      </div>
83	    </div>
84	  );
85	};
86	
87	export const TagsDetails: React.FC<TagsDetailsProps> = ({ obj }) => {
88	  const { userName, iamClient, fresh } = obj;
89	
90	  return fresh ? (
91	    <TagsDetailsContent userName={userName} iamClient={iamClient} />
92	  ) : (
93	    <LoadingBox />
94	  );
95	};

